(window.webpackJsonp=window.webpackJsonp||[]).push([[72],{1345:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-class\\"><span class=\\"hljs-keyword\\">class</span> <span class=\\"hljs-title\\">Solution</span><span class=\\"hljs-params\\">(object)</span>:</span>\\n    <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">def</span> <span class=\\"hljs-title\\">maxProfit</span><span class=\\"hljs-params\\">(self, prices, fee)</span>:</span>\\n        <span class=\\"hljs-string\\">\\"\\"\\"\\n        :type prices: List[int]\\n        :type fee: int\\n        :rtype: int\\n        \\"\\"\\"</span>\\n        n=len(prices)\\n        <span class=\\"hljs-comment\\"># dp=[[0]*n for i in range(2)]</span>\\n        <span class=\\"hljs-comment\\"># dp[1][0]=-prices[0]</span>\\n        <span class=\\"hljs-comment\\"># for i in range(1,n):</span>\\n        <span class=\\"hljs-comment\\">#     dp[0][i]=max(dp[0][i-1],prices[i]+dp[1][i-1]-fee)</span>\\n        <span class=\\"hljs-comment\\">#     dp[1][i]=max(dp[0][i-1]-prices[i],dp[1][i-1])</span>\\n        <span class=\\"hljs-comment\\"># # print dp</span>\\n        <span class=\\"hljs-comment\\"># return dp[0][-1]</span>\\n        sell,buy=<span class=\\"hljs-number\\">0</span>,-prices[<span class=\\"hljs-number\\">0</span>]\\n        <span class=\\"hljs-keyword\\">for</span> i <span class=\\"hljs-keyword\\">in</span> range(<span class=\\"hljs-number\\">1</span>,n):\\n          last_sell=sell\\n          last_buy=buy\\n          sell=max(last_sell,prices[i]+last_buy-fee)\\n          buy=max(last_buy,last_sell-prices[i])\\n        \\n        <span class=\\"hljs-keyword\\">return</span> sell\\n</code></pre>\\n"],"titleSlug":"best-time-to-buy-and-sell-stock-with-transaction-fee","hasThinking":false,"content":"<p>\u7ed9\u5b9a\u4e00\u4e2a\u6574\u6570\u6570\u7ec4&nbsp;<code>prices</code>\uff0c\u5176\u4e2d\u7b2c&nbsp;<code>i</code>&nbsp;\u4e2a\u5143\u7d20\u4ee3\u8868\u4e86\u7b2c&nbsp;<code>i</code>&nbsp;\u5929\u7684\u80a1\u7968\u4ef7\u683c \uff1b\u975e\u8d1f\u6574\u6570&nbsp;<code>fee</code> \u4ee3\u8868\u4e86\u4ea4\u6613\u80a1\u7968\u7684\u624b\u7eed\u8d39\u7528\u3002</p>\\n\\n<p>\u4f60\u53ef\u4ee5\u65e0\u9650\u6b21\u5730\u5b8c\u6210\u4ea4\u6613\uff0c\u4f46\u662f\u4f60\u6bcf\u7b14\u4ea4\u6613\u90fd\u9700\u8981\u4ed8\u624b\u7eed\u8d39\u3002\u5982\u679c\u4f60\u5df2\u7ecf\u8d2d\u4e70\u4e86\u4e00\u4e2a\u80a1\u7968\uff0c\u5728\u5356\u51fa\u5b83\u4e4b\u524d\u4f60\u5c31\u4e0d\u80fd\u518d\u7ee7\u7eed\u8d2d\u4e70\u80a1\u7968\u4e86\u3002</p>\\n\\n<p>\u8fd4\u56de\u83b7\u5f97\u5229\u6da6\u7684\u6700\u5927\u503c\u3002</p>\\n\\n<p><strong>\u6ce8\u610f\uff1a</strong>\u8fd9\u91cc\u7684\u4e00\u7b14\u4ea4\u6613\u6307\u4e70\u5165\u6301\u6709\u5e76\u5356\u51fa\u80a1\u7968\u7684\u6574\u4e2a\u8fc7\u7a0b\uff0c\u6bcf\u7b14\u4ea4\u6613\u4f60\u53ea\u9700\u8981\u4e3a\u652f\u4ed8\u4e00\u6b21\u624b\u7eed\u8d39\u3002</p>\\n\\n<p><strong>\u793a\u4f8b 1:</strong></p>\\n\\n<pre><strong>\u8f93\u5165:</strong> prices = [1, 3, 2, 8, 4, 9], fee = 2\\n<strong>\u8f93\u51fa:</strong> 8\\n<strong>\u89e3\u91ca:</strong> \u80fd\u591f\u8fbe\u5230\u7684\u6700\u5927\u5229\u6da6:  \\n\u5728\u6b64\u5904\u4e70\u5165&nbsp;prices[0] = 1\\n\u5728\u6b64\u5904\u5356\u51fa prices[3] = 8\\n\u5728\u6b64\u5904\u4e70\u5165 prices[4] = 4\\n\u5728\u6b64\u5904\u5356\u51fa prices[5] = 9\\n\u603b\u5229\u6da6:&nbsp;((8 - 1) - 2) + ((9 - 4) - 2) = 8.</pre>\\n\\n<p><strong>\u6ce8\u610f:</strong></p>\\n\\n<ul>\\n\\t<li><code>0 &lt; prices.length &lt;= 50000</code>.</li>\\n\\t<li><code>0 &lt; prices[i] &lt; 50000</code>.</li>\\n\\t<li><code>0 &lt;= fee &lt; 50000</code>.</li>\\n</ul>\\n","title":"714. \u4e70\u5356\u80a1\u7968\u7684\u6700\u4f73\u65f6\u673a\u542b\u624b\u7eed\u8d39","relatedTags":["\u8d2a\u5fc3\u7b97\u6cd5","\u6570\u7ec4","\u52a8\u6001\u89c4\u5212"],"difficult":"Middle","lang":["python"],"uniqueID":"714"}')}}]);